# compute token-level LCS length between candidate and full
def lcs_len(a_tokens, b_tokens):
    n=len(a_tokens); m=len(b_tokens)
    # DP iterative
    dp = [[0]*(m+1) for _ in range(n+1)]
    for i in range(n-1,-1,-1):
        for j in range(m-1,-1,-1):
            if a_tokens[i]==b_tokens[j]:
                dp[i][j] = 1 + dp[i+1][j+1]
            else:
                dp[i][j] = max(dp[i+1][j], dp[i][j+1])
    return dp[0][0]

